import anthropic

client = anthropic.Anthropic()

def run_react_agent(user_message, tools, tool_handlers, max_iter=10):
    messages = [{"role": "user", "content": user_message}]

    for step in range(max_iter):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=tools,
            messages=messages
        )

        print(f"--- Крок {step + 1} | stop_reason: {response.stop_reason} ---")

        # Додаємо відповідь асистента до історії
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Агент завершив — повертаємо текстову відповідь
            for block in response.content:
                if hasattr(block, 'text'):
                    return block.text

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    print(f"  Action: {block.name}({block.input})")
                    result = tool_handlers[block.name](**block.input)
                    print(f"  Observation: {result}")
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": str(result)
                    })
            messages.append({"role": "user", "content": tool_results})

    return "Перевищено максимальну кількість ітерацій"

import anthropic
from typing import Callable

class SimpleAgent:
    def __init__(self, tools: list, handlers: dict[str, Callable], system: str = "", max_iter: int = 10):
        self.client = anthropic.Anthropic()
        self.tools = tools
        self.handlers = handlers  # {"tool_name": handler_fn}
        self.system = system
        self.max_iter = max_iter

    def run(self, user_message: str) -> str:
        messages = [{"role": "user", "content": user_message}]

        for _ in range(self.max_iter):
            kwargs = {"model": "claude-sonnet-4-6", "max_tokens": 1024,
                      "tools": self.tools, "messages": messages}
            if self.system:
                kwargs["system"] = self.system

            response = self.client.messages.create(**kwargs)
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                return next((b.text for b in response.content if hasattr(b, 'text')), "")

            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    fn = self.handlers.get(block.name)
                    result = fn(**block.input) if fn else f"Unknown tool: {block.name}"
                    tool_results.append({"type": "tool_result",
                                         "tool_use_id": block.id, "content": str(result)})
            messages.append({"role": "user", "content": tool_results})

        return "Ліміт ітерацій досягнуто"


