import functools
import time
from typing import Callable

def trace_tool(fn: Callable) -> Callable:
    """Декоратор що логує виклики інструментів."""
    @functools.wraps(fn)
    def wrapper(**kwargs):
        start = time.time()
        print(f"  → {fn.__name__}({kwargs})")
        try:
            result = fn(**kwargs)
            elapsed = (time.time() - start) * 1000
            print(f"  ← {fn.__name__} [{elapsed:.0f}ms]: {str(result)[:100]}")
            return result
        except Exception as e:
            print(f"  ✗ {fn.__name__} ERROR: {e}")
            return f"ERROR: {e}"  # повертаємо помилку як рядок, не кидаємо виняток
    return wrapper


def safe_agent_run(agent_fn, user_message, max_retries=3):
    """Запускає агента з retry при API помилках."""
    for attempt in range(max_retries):
        try:
            return agent_fn(user_message)
        except Exception as e:
            if "rate_limit" in str(e).lower() and attempt < max_retries - 1:
                wait = 2 ** attempt  # 1s, 2s, 4s
                print(f"Rate limit, чекаємо {wait}s...")
                time.sleep(wait)
            else:
                return f"Помилка після {attempt + 1} спроб: {e}"


# Приклад використання:
@trace_tool
def search(query: str) -> str:
    # Симулюємо помилку для демонстрації
    if "error" in query.lower():
        raise ValueError("Search service unavailable")
    return f"Results for: {query}"

# Тепер search логує кожен виклик і безпечно обробляє помилки

import anthropic
import json

client = anthropic.Anthropic()

def worker(task: str, feedback: str = '') -> str:
    prompt = task
    if feedback:
        prompt += "\n\nПопередня спроба мала проблеми: " + feedback + "\nВиправ їх."
    resp = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=400,
        system="Ти автор. Пиши чіткі структуровані тексти.",
        messages=[{"role": "user", "content": prompt}]
    )
    return resp.content[0].text

def supervisor(result: str, criteria: str) -> dict:
    prompt = (
        "Оціни текст за критеріями: " + criteria + "\n\n"
        "Текст для оцінки:\n" + result + "\n\n"
        'Поверни JSON: {"approved": true/false, "score": 1-10, "issues": ["..."]}'
    )
    resp = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=200,
        system="Ти суворий редактор. Оцінюй об'єктивно.",
        messages=[{"role": "user", "content": prompt}]
    )
    try:
        text = resp.content[0].text
        start = text.index('{')
        end = text.rindex('}') + 1
        return json.loads(text[start:end])
    except Exception:
        return {"approved": False, "score": 0, "issues": ["Supervisor parse error"]}

def supervised_run(task: str, criteria: str, max_retries: int = 3) -> str:
    feedback = ''
    best_result, best_score = '', 0
    for attempt in range(1, max_retries + 1):
        result = worker(task, feedback)
        evaluation = supervisor(result, criteria)
        print(f"Attempt {attempt}: score={evaluation['score']}, approved={evaluation['approved']}")
        if evaluation['score'] > best_score:
            best_result, best_score = result, evaluation['score']
        if evaluation['approved']:
            return result
        feedback = ', '.join(evaluation.get('issues', []))
    return best_result

result = supervised_run(
    task="Напиши вступ до статті про мультиагентні системи",
    criteria="має бути 3-5 речень, без жаргону, з конкретним прикладом"
)
print(result)

import anthropic

client = anthropic.Anthropic()

def call_agent(system: str, user: str, max_tokens: int = 300) -> str:
    resp = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=max_tokens,
        system=system,
        messages=[{"role": "user", "content": user}]
    )
    return resp.content[0].text

def triage_agent(state: dict) -> dict:
    query = state["query"]
    decision = call_agent(
        system="Визнач тему запиту. Відповідай ТІЛЬКИ одним словом: tech, finance, або general",
        user=query
    ).strip().lower()
    state["route"] = decision if decision in ["tech", "finance"] else "general"
    print(f"[Triage] routing to: {state['route']}")
    return state

def tech_agent(state: dict) -> dict:
    state["answer"] = call_agent(
        system="Ти технічний експерт. Давай точні технічні відповіді.",
        user=state["query"]
    )
    print("[Tech] answered")
    return state

def finance_agent(state: dict) -> dict:
    state["answer"] = call_agent(
        system="Ти фінансовий аналітик. Аналізуй ринки та фінанси.",
        user=state["query"]
    )
    print("[Finance] answered")
    return state

def general_agent(state: dict) -> dict:
    state["answer"] = call_agent(
        system="Ти помічник загального призначення.",
        user=state["query"]
    )
    print("[General] answered")
    return state

AGENTS = {
    "triage": triage_agent,
    "tech": tech_agent,
    "finance": finance_agent,
    "general": general_agent
}

def run_swarm(query: str) -> str:
    state = {"query": query, "route": "triage", "answer": ""}
    # Починаємо з triage, далі агенти вирішують самостійно
    for agent_name in ["triage", state.get("route", "general")]:
        fn = AGENTS.get(agent_name)
        if fn:
            state = fn(state)
    return state.get("answer", "Немає відповіді")

print(run_swarm("Як інвестувати в ETF?"))
