import anthropic
import json

client = anthropic.Anthropic()

# Зовнішній scratchpad поза messages
scratchpad = {}

tools = [
    {
        "name": "write_scratchpad",
        "description": "Зберігає значення в scratchpad за ключем",
        "input_schema": {"type": "object",
                         "properties": {"key": {"type": "string"}, "value": {"type": "string"}},
                         "required": ["key", "value"]}
    },
    {
        "name": "read_scratchpad",
        "description": "Читає значення зі scratchpad за ключем",
        "input_schema": {"type": "object",
                         "properties": {"key": {"type": "string"}},
                         "required": ["key"]}
    }
]

def handle_tool(name: str, inp: dict) -> str:
    if name == "write_scratchpad":
        scratchpad[inp["key"]] = inp["value"]
        return f"Saved: {inp['key']} = {inp['value']}"
    elif name == "read_scratchpad":
        return scratchpad.get(inp["key"], "Not found")
    return "Unknown tool"

def run_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    for _ in range(8):
        resp = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=600,
            system="Використовуй scratchpad для збереження проміжних результатів.",
            tools=tools, messages=messages
        )
        messages.append({"role": "assistant", "content": resp.content})
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if hasattr(b, 'text')), '')
        results = []
        for b in resp.content:
            if b.type == "tool_use":
                result = handle_tool(b.name, b.input)
                results.append({"type": "tool_result", "tool_use_id": b.id, "content": result})
        messages.append({"role": "user", "content": results})
    return "Ліміт ітерацій"

print(run_agent("Порахуй суму чисел від 1 до 5, зберігаючи проміжні результати у scratchpad"))
print("Final scratchpad:", scratchpad)
